import React, {isValidElement} from 'react';
import AlertEl, {AlertDescription, AlertIcon, AlertTitle} from './alert';
import type {IAlertProps} from "@lmb-it/kitsconcerto-types";
import {useKitsTheme} from "../../contexts/Theme";

const Alert = ({status = 'info', variant = 'subtle', className, withIcon, children, title, description}: IAlertProps) => {
    const {resolveToken} = useKitsTheme();
    const primary = resolveToken('primary');

    const statusColors: Record<string, string> = {
        error: resolveToken('red.500'),
        success: resolveToken('green.500'),
        warning: resolveToken('yellow.500'),
        info: resolveToken('blue.500'),
        brand: primary,
    };

    const color = statusColors[status!];
    const textColor = variant === "solid" ? "#FFFFFF" : color;

    return (
        <AlertEl status={status} className={className} variant={variant}>
            {withIcon && <AlertIcon status={status}/>}
            {title && <AlertTitle color={textColor}>{title}</AlertTitle>}
            {description && <AlertDescription color={textColor}>{description}</AlertDescription>}
            {typeof children == "string" && <AlertTitle color={textColor}>{children}</AlertTitle>}
            {isValidElement(children) && children}
        </AlertEl>
    );
};

export {AlertIcon, AlertTitle, AlertDescription};
export default Alert;
